const client = $('Batch Clients').item.json;
const trendsData = $input.item.json;
const results = [];

// Extract trending topics from interest_over_time or related_queries
const relatedQueries = trendsData.related_queries?.rising || [];
const relatedTopics = trendsData.related_topics?.rising || [];

const topics = [...relatedQueries, ...relatedTopics].slice(0, 10);

for (const topic of topics) {
  results.push({
    json: {
      client_id: client.client_id,
      topic: topic.query || topic.topic?.title || 'Unknown',
      trend_score: topic.value || 0,
      source: 'google-trends',
      category: 'rising'
    }
  });
}

// If no API results, generate from keywords
if (results.length === 0 && client.top_keywords) {
  for (const kw of (client.top_keywords || []).slice(0, 5)) {
    results.push({
      json: {
        client_id: client.client_id,
        topic: `${kw} best practices 2026`,
        trend_score: Math.floor(Math.random() * 80) + 20,
        source: 'keyword-derived',
        category: 'evergreen'
      }
    });
  }
}

return results;
